package com.careeros.provider.infrastructure;import com.careeros.provider.domain.*;import org.springframework.data.domain.*;import org.springframework.data.jpa.repository.*;import org.springframework.stereotype.Repository;import java.util.*;
interface SpringDataSyncHistoryRepository extends JpaRepository<SyncHistory,UUID>{@EntityGraph(attributePaths="company")Page<SyncHistory>findByCompanyId(UUID id,Pageable p);@EntityGraph(attributePaths="company")Page<SyncHistory>findByProvider(ProviderType provider,Pageable p);@EntityGraph(attributePaths="company")Page<SyncHistory>findAll(Pageable p);@EntityGraph(attributePaths="company")List<SyncHistory>findAll();}
@Repository class SyncHistoryRepositoryAdapter implements SyncHistoryRepository{private final SpringDataSyncHistoryRepository r;SyncHistoryRepositoryAdapter(SpringDataSyncHistoryRepository r){this.r=r;}public SyncHistory save(SyncHistory h){return r.save(h);}public Page<SyncHistory>findAll(Pageable p){return r.findAll(p);}public Page<SyncHistory>findByCompanyId(UUID id,Pageable p){return r.findByCompanyId(id,p);}public Page<SyncHistory>findByProvider(ProviderType t,Pageable p){return r.findByProvider(t,p);}public List<SyncHistory>findAll(){return r.findAll();}}
